import { watch } from 'node:fs';
import { relative, resolve, sep } from 'node:path';
import { loadBrowserConfig } from './config/load.js';
import { runMach } from './mach.js';
import { prepareProject } from './prepare.js';
const NATIVE_OR_BUILD_FILE = /(?:^|\/)(?:moz\.build|moz\.configure|configure\.py|Cargo\.toml)$|\.(?:c|cc|cpp|cxx|h|hh|hpp|rs|idl|webidl)$/i;
const FIREFOX_FRONTEND_FILE = /\.(?:js|mjs|jsm|css|html|xhtml|xml|xul|ftl|properties|json|png|jpe?g|gif|svg|ico|webp|avif|woff2?)$/i;
const PROFILE_STYLE = /^src\/browser\/styles\/(?:browser|content)\.css$/;
export function devAction(paths) {
    let action = 'restart';
    for (const path of paths) {
        if (path === 'browser.config.json' ||
            path.startsWith('patches/') ||
            NATIVE_OR_BUILD_FILE.test(path) ||
            (path.startsWith('src/firefox/') && !FIREFOX_FRONTEND_FILE.test(path)))
            return 'full';
        if (!PROFILE_STYLE.test(path))
            action = 'fast';
    }
    return action;
}
const ACTION_RANK = { restart: 0, fast: 1, full: 2 };
function stronger(current, next) {
    return current && ACTION_RANK[current] > ACTION_RANK[next] ? current : next;
}
export async function devProject(cwd = process.cwd(), externalSignal) {
    const project = resolve(cwd);
    const config = await loadBrowserConfig(project);
    await prepareProject(project);
    const controller = new AbortController();
    const stop = () => controller.abort();
    if (externalSignal?.aborted)
        stop();
    else if (externalSignal)
        externalSignal.addEventListener('abort', stop, { once: true });
    else {
        process.once('SIGINT', stop);
        process.once('SIGTERM', stop);
    }
    let pending;
    let timer;
    let processing;
    let browserAbort;
    let browser;
    const launch = () => {
        browserAbort = new AbortController();
        browser = runMach(['run'], project, browserAbort.signal).catch((error) => {
            console.error(error instanceof Error ? error.message : String(error));
            return 1;
        });
    };
    const stopBrowser = async () => {
        browserAbort?.abort();
        await browser;
        browserAbort = undefined;
        browser = undefined;
    };
    const rebuild = async () => {
        try {
            while (pending && !controller.signal.aborted) {
                const action = pending;
                pending = undefined;
                await stopBrowser();
                if (action !== 'restart') {
                    await prepareProject(project);
                    const code = await runMach(action === 'full' ? ['build'] : ['build', 'faster'], project, controller.signal);
                    if (code !== 0 || controller.signal.aborted)
                        continue;
                }
                launch();
            }
        }
        catch (error) {
            console.error(error instanceof Error ? error.message : String(error));
        }
        finally {
            processing = undefined;
        }
    };
    const changed = (path, action = devAction([path])) => {
        pending = stronger(pending, action);
        if (timer)
            clearTimeout(timer);
        timer = setTimeout(() => {
            timer = undefined;
            if (!processing)
                processing = rebuild();
        }, 150);
    };
    const watchers = [];
    const addDirectory = (directory, action) => {
        const absolute = resolve(project, directory);
        watchers.push(watch(absolute, { recursive: true }, (_event, filename) => {
            const path = filename ? resolve(absolute, String(filename)) : absolute;
            const projectPath = relative(project, path).split(sep).join('/');
            changed(projectPath, action ?? devAction([projectPath]));
        }));
    };
    addDirectory('src/browser');
    addDirectory(config.overlays.directory);
    addDirectory('prefs');
    addDirectory(config.patches.directory, 'full');
    addDirectory(config.branding.directory, 'fast');
    watchers.push(watch(project, (_event, filename) => {
        if (String(filename) === 'browser.config.json')
            changed('browser.config.json');
    }));
    launch();
    console.log('Watching project files. Press Ctrl+C to stop.');
    await new Promise((resolveDone) => {
        if (controller.signal.aborted)
            resolveDone();
        else
            controller.signal.addEventListener('abort', () => resolveDone(), { once: true });
    });
    if (timer)
        clearTimeout(timer);
    pending = undefined;
    for (const watcher of watchers)
        watcher.close();
    await stopBrowser();
    await processing;
    if (externalSignal)
        externalSignal.removeEventListener('abort', stop);
    else {
        process.off('SIGINT', stop);
        process.off('SIGTERM', stop);
    }
    return 0;
}
